class FoodRatings {
public:
    unordered_map<string, unordered_map<string, pair<int, string>>> ratingMap;
    FoodRatings(vector<string>& foods, vector<string>& cuisines, vector<int>& ratings) {
        for (int i = 0; i < foods.size(); i++) {
            ratingMap[ foods[i] ][ cuisines[i] ] = {ratings[i], foods[i]};
        }
    }

    void changeRating(string food, int newRating) {
        if (ratingMap.find(food) == ratingMap.end()) return;
        string cuisine = ratingMap[food].begin()->first;
        ratingMap[food][cuisine].first = newRating;
        sort(ratingMap[food][cuisine].begin(), ratingMap[food][cuisine].end());
    }

    string highestRated(string cuisine) {
        string res = "";
        int maxRating = 0;
        for (auto& p : ratingMap) {
            if (p.second.find(cuisine) != p.second.end() && p.second[cuisine].first > maxRating) {
                maxRating = p.second[cuisine].first;
                res = p.second[cuisine].second;
            }
        }
        return res;
    }
};
```
